kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;
constexpr uint32_t VEC_SIZE = 64;   // AscendC vector length in floats

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t outerSize,
                                uint32_t innerSize, uint32_t tileLength,
                                uint32_t blockDim) {
        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLength);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLength);
        outerSize_ = outerSize;
        innerSize_ = innerSize;
        tileLen_ = tileLength;
        blockDim_ = blockDim;
        totalLen_ = totalLength;
        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(scalarQueue_, 1, 1 * sizeof(float));
        // for per-tile reduction results (scalar)
        pipe_.InitBuffer(tileMax_, 1, 1 * sizeof(float));
        pipe_.InitBuffer(tileSum_, 1, 1 * sizeof(float));
    }

    __aicore__ inline void Process() {
        if (totalLen_ == 0 || innerSize_ == 0) return;

        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t blockNum = blockDim_;

        for (uint32_t outerIdx = blockIdx; outerIdx < outerSize_; outerIdx += blockNum) {
            uint32_t baseOffset = outerIdx * innerSize_;
            float mx = ComputeMax(baseOffset);
            float sumExp = ComputeSumExp(baseOffset, mx);
            ComputeOutput(baseOffset, mx, sumExp);
        }
    }

private:
    __aicore__ inline float ComputeMax(uint32_t baseOffset) {
        // Initialize max to a very small number
        AscendC::LocalTensor<float> maxScalar = scalarQueue_.AllocTensor<float>();
        maxScalar.SetValue(0, -1e38f);
        uint32_t remaining = innerSize_;
        uint32_t offset = baseOffset;

        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], curLen);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> tileMax = tileMax_.AllocTensor<float>();
            // ReduceMax with explicit pattern, repeat = curLen / VEC_SIZE
            uint32_t repeat = curLen / VEC_SIZE;
            if (repeat > 0) {
                AscendC::ReduceMax<AscendC::REDUCE_MAX>(tileMax, xLocal, repeat);
                // Compare with current max
                AscendC::Max(maxScalar, maxScalar, tileMax, 1);
            } else {
                // curLen < 64: simple scalar loop
                float val = xLocal(0);
                float curMax = maxScalar(0);
                if (val > curMax) maxScalar.SetValue(0, val);
            }
            tileMax_.FreeTensor(tileMax);
            inQueueX_.FreeTensor(xLocal);

            offset += curLen;
            remaining -= curLen;
        }
        float result = maxScalar(0);
        scalarQueue_.FreeTensor(maxScalar);
        return result;
    }

    __aicore__ inline float ComputeSumExp(uint32_t baseOffset, float mx) {
        AscendC::LocalTensor<float> sumScalar = scalarQueue_.AllocTensor<float>();
        sumScalar.SetValue(0, 0.0f);
        uint32_t remaining = innerSize_;
        uint32_t offset = baseOffset;

        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], curLen);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> tLocal = tmpQueue_.AllocTensor<float>();
            // x - mx (use Add with negative)
            AscendC::Add(tLocal, xLocal, -mx, curLen);
            // exp
            AscendC::Exp(tLocal, tLocal, curLen);
            // ReduceSum
            uint32_t repeat = curLen / VEC_SIZE;
            if (repeat > 0) {
                AscendC::LocalTensor<float> tileSum = tileSum_.AllocTensor<float>();
                AscendC::ReduceSum<AscendC::REDUCE_SUM>(tileSum, tLocal, repeat);
                AscendC::Add(sumScalar, sumScalar, tileSum, 1);
                tileSum_.FreeTensor(tileSum);
            } else {
                sumScalar.SetValue(0, sumScalar(0) + tLocal(0));
            }
            tmpQueue_.FreeTensor(tLocal);
            inQueueX_.FreeTensor(xLocal);

            offset += curLen;
            remaining -= curLen;
        }
        float result = sumScalar(0);
        scalarQueue_.FreeTensor(sumScalar);
        return result;
    }

    __aicore__ inline void ComputeOutput(uint32_t baseOffset, float mx, float sumExp) {
        // Compute logSum = log(sumExp) as a scalar
        AscendC::LocalTensor<float> logScalar = scalarQueue_.AllocTensor<float>();
        logScalar.SetValue(0, sumExp);
        AscendC::Log(logScalar, logScalar, 1);
        float logSum = logScalar(0);
        scalarQueue_.FreeTensor(logScalar);

        uint32_t remaining = innerSize_;
        uint32_t offset = baseOffset;

        while (remaining > 0) {
            uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
            AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
            AscendC::DataCopy(xLocal, xGm_[offset], curLen);
            inQueueX_.EnQue(xLocal);

            xLocal = inQueueX_.DeQue<float>();
            AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
            AscendC::LocalTensor<float> tLocal = tmpQueue_.AllocTensor<float>();
            // y = x - mx - logSum = x + (-mx) + (-logSum)
            AscendC::Add(tLocal, xLocal, -mx, curLen);
            AscendC::Add(yLocal, tLocal, -logSum, curLen);

            outQueueY_.EnQue<float>(yLocal);
            tmpQueue_.FreeTensor(tLocal);
            inQueueX_.FreeTensor(xLocal);

            // Copy out
            yLocal = outQueueY_.DeQue<float>();
            AscendC::DataCopy(yGm_[offset], yLocal, curLen);
            outQueueY_.FreeTensor(yLocal);

            offset += curLen;
            remaining -= curLen;
        }
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> scalarQueue_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tileMax_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tileSum_;
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;
    uint32_t outerSize_ {0};
    uint32_t innerSize_ {0};
    uint32_t tileLen_ {0};
    uint32_t blockDim_ {1};
    uint32_t totalLen_ {0};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.outerSize,
            tiling_data.innerSize, tiling_data.tileLength, tiling_data.blockDim);
    op.Process();
}
